pub type DevnetResult<T> = Result<T, String>;

pub const DEVNET_RUNNER_VERSION: &str = "nebula-l2-devnet-runner-v1";
pub const DEVNET_DEFAULT_BLOCKS: u64 = 6;
pub const DEVNET_DEFAULT_FEE_QUOTE_INTERVAL: u64 = 2;
pub const DEVNET_DEFAULT_SYNC_INTERVAL: u64 = 3;
pub const DEVNET_DEFAULT_RELAYER_INTERVAL: u64 = 2;
pub const DEVNET_DEFAULT_RPC_TTL_BLOCKS: u64 = 20;

#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub enum DevnetStepKind {
    Start,
    Tick,
    ProduceBlock,
    FeeQuote,
    RpcStatus,
    P2pHandshake,
    P2pSync,
    P2pGossip,
    RelayerAnchor,
    RelayerObservation,
    WorkloadBatch,
    StorageSnapshot,
    MvpControlGate,
    MvpPrivateFlow,
    Stop,
}

impl DevnetStepKind {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Start => "start",
            Self::Tick => "tick",
            Self::ProduceBlock => "produce_block",
            Self::FeeQuote => "fee_quote",
            Self::RpcStatus => "rpc_status",
            Self::P2pHandshake => "p2p_handshake",
            Self::P2pSync => "p2p_sync",
            Self::P2pGossip => "p2p_gossip",
            Self::RelayerAnchor => "relayer_anchor",
            Self::RelayerObservation => "relayer_observation",
            Self::WorkloadBatch => "workload_batch",
            Self::StorageSnapshot => "storage_snapshot",
            Self::MvpControlGate => "mvp_control_gate",
            Self::MvpPrivateFlow => "mvp_private_flow",
            Self::Stop => "stop",
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct DevnetRunConfig {
    pub run_id: String,
    pub operator_label: String,
    pub blocks: u64,
    pub start_timestamp_ms: u64,
    pub block_time_ms: u64,
    pub fee_quote_interval_blocks: u64,
    pub p2p_sync_interval_blocks: u64,
    pub relayer_interval_blocks: u64,
    pub produce_empty_blocks: bool,
    pub enable_rpc: bool,
    pub enable_p2p: bool,
    pub enable_relayer: bool,
    pub enable_storage_snapshots: bool,
    pub enable_workload: bool,
    pub workload_batch_size: u64,
    pub low_fee_gross_fee_units: u64,
    pub p2p_route_hint: String,
    pub monero_network: String,
    pub privacy_mode: String,
}

impl DevnetRunConfig {
    pub fn new(operator_label: impl Into<String>) -> Self {
        let operator_label = operator_label.into();
        let run_id = devnet_run_id(
            &operator_label,
            DEVNET_DEFAULT_BLOCKS,
            1_700_000_000_000,
            TARGET_BLOCK_MS,
        );
        Self {
            run_id,
            operator_label,
            blocks: DEVNET_DEFAULT_BLOCKS,
            start_timestamp_ms: 1_700_000_000_000,
            block_time_ms: TARGET_BLOCK_MS,
            fee_quote_interval_blocks: DEVNET_DEFAULT_FEE_QUOTE_INTERVAL,
            p2p_sync_interval_blocks: DEVNET_DEFAULT_SYNC_INTERVAL,
            relayer_interval_blocks: DEVNET_DEFAULT_RELAYER_INTERVAL,
            produce_empty_blocks: true,
            enable_rpc: true,
            enable_p2p: true,
            enable_relayer: true,
            enable_storage_snapshots: true,
            enable_workload: true,
            workload_batch_size: 24,
            low_fee_gross_fee_units: 25_000,
            p2p_route_hint: "in-process-devnet".to_string(),
            monero_network: "monero-devnet".to_string(),
            privacy_mode: "payload_roots_only".to_string(),
        }
    }

    pub fn with_blocks(mut self, blocks: u64) -> Self {
        self.blocks = blocks.max(1);
        self.refresh_run_id();
        self
    }

    pub fn with_operator_label(mut self, operator_label: impl Into<String>) -> Self {
        self.operator_label = operator_label.into();
        self.refresh_run_id();
        self
    }

    pub fn with_start_timestamp_ms(mut self, start_timestamp_ms: u64) -> Self {
        self.start_timestamp_ms = start_timestamp_ms;
        self.refresh_run_id();
        self
    }

    pub fn with_block_time_ms(mut self, block_time_ms: u64) -> Self {
        self.block_time_ms = block_time_ms.max(1);
        self.refresh_run_id();
        self
    }

    pub fn with_rpc(mut self, enabled: bool) -> Self {
        self.enable_rpc = enabled;
        self
    }

    pub fn with_p2p(mut self, enabled: bool) -> Self {
        self.enable_p2p = enabled;
        self
    }

    pub fn with_relayer(mut self, enabled: bool) -> Self {
        self.enable_relayer = enabled;
        self
    }

    pub fn with_workload(mut self, enabled: bool) -> Self {
        self.enable_workload = enabled;
        self
    }

    pub fn with_workload_batch_size(mut self, workload_batch_size: u64) -> Self {
        self.workload_batch_size = workload_batch_size.max(1);
        self
    }

    pub fn timestamp_for_height(&self, height: u64) -> u64 {
        self.start_timestamp_ms
            .saturating_add(height.saturating_mul(self.block_time_ms))
    }

    pub fn public_record(&self) -> Value {
        json!({
            "kind": "devnet_run_config",
            "chain_id": CHAIN_ID,
            "devnet_runner_version": DEVNET_RUNNER_VERSION,
            "run_id": self.run_id,
            "operator_label": self.operator_label,
            "blocks": self.blocks,
            "start_timestamp_ms": self.start_timestamp_ms,
            "block_time_ms": self.block_time_ms,
            "fee_quote_interval_blocks": self.fee_quote_interval_blocks,
            "p2p_sync_interval_blocks": self.p2p_sync_interval_blocks,
            "relayer_interval_blocks": self.relayer_interval_blocks,
            "produce_empty_blocks": self.produce_empty_blocks,
            "enable_rpc": self.enable_rpc,
            "enable_p2p": self.enable_p2p,
            "enable_relayer": self.enable_relayer,
            "enable_storage_snapshots": self.enable_storage_snapshots,
            "enable_workload": self.enable_workload,
            "workload_batch_size": self.workload_batch_size,
            "low_fee_gross_fee_units": self.low_fee_gross_fee_units,
            "p2p_route_commitment": devnet_payload_root("DEVNET-P2P-ROUTE", &json!({ "route": self.p2p_route_hint })),
            "monero_network": self.monero_network,
            "privacy_mode": self.privacy_mode,
        })
    }

    pub fn config_root(&self) -> String {
        domain_hash(
            "DEVNET-RUN-CONFIG",
            &[HashPart::Json(&self.public_record())],
            32,
        )
    }

    fn refresh_run_id(&mut self) {
        self.run_id = devnet_run_id(
            &self.operator_label,
            self.blocks,
            self.start_timestamp_ms,
            self.block_time_ms,
        );
    }
}

impl Default for DevnetRunConfig {
    fn default() -> Self {
        Self::new("devnet-operator")
    }
}

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct DevnetStepReceipt {
    pub step_id: String,
    pub run_id: String,
    pub step_index: u64,
    pub step_kind: DevnetStepKind,
    pub height: u64,
    pub timestamp_ms: u64,
    pub request_root: String,
    pub response_root: String,
    pub daemon_root: String,
    pub rpc_root: String,
    pub p2p_root: String,
    pub relayer_root: String,
    pub status: String,
}

impl DevnetStepReceipt {
    #[allow(clippy::too_many_arguments)]
    pub fn new(
        run_id: &str,
        step_index: u64,
        step_kind: DevnetStepKind,
        height: u64,
        timestamp_ms: u64,
        request: &Value,
        response: &Value,
        daemon_root: &str,
        rpc_root: &str,
        p2p_root: &str,
        relayer_root: &str,
        status: &str,
    ) -> Self {
        let request_root = devnet_payload_root("DEVNET-STEP-REQUEST", request);
        let response_root = devnet_payload_root("DEVNET-STEP-RESPONSE", response);
        let step_id = devnet_step_id(
            run_id,
            step_index,
            step_kind.as_str(),
            height,
            &request_root,
            &response_root,
        );
        Self {
            step_id,
            run_id: run_id.to_string(),
            step_index,
            step_kind,
            height,
            timestamp_ms,
            request_root,
            response_root,
            daemon_root: daemon_root.to_string(),
            rpc_root: rpc_root.to_string(),
            p2p_root: p2p_root.to_string(),
            relayer_root: relayer_root.to_string(),
            status: status.to_string(),
        }
    }

    pub fn public_record(&self) -> Value {
        json!({
            "kind": "devnet_step_receipt",
            "chain_id": CHAIN_ID,
            "devnet_runner_version": DEVNET_RUNNER_VERSION,
            "step_id": self.step_id,
            "run_id": self.run_id,
            "step_index": self.step_index,
            "step_kind": self.step_kind.as_str(),
            "height": self.height,
            "timestamp_ms": self.timestamp_ms,
            "request_root": self.request_root,
            "response_root": self.response_root,
            "daemon_root": self.daemon_root,
            "rpc_root": self.rpc_root,
            "p2p_root": self.p2p_root,
            "relayer_root": self.relayer_root,
            "status": self.status,
        })
    }

    pub fn receipt_root(&self) -> String {
        domain_hash(
            "DEVNET-STEP-RECEIPT",
            &[HashPart::Json(&self.public_record())],
            32,
        )
    }
}

