        let operator_update = self.supervise_operator_for_block(&summary)?;
        self.rpc.set_height(self.daemon.node.height());
        self.rpc.set_api_state(&self.daemon.api);
        self.rpc.set_block_production_root(devnet_payload_root(
            "DEVNET-BLOCK",
            &summary.public_record(),
        ));
