    pub fn run_rpc_status(&mut self, height: u64) -> DevnetResult<RpcResponse> {
        let payload = self.daemon.public_record();
        let request = RpcRequest::from_payload(
            RpcMethod::Status,
            &payload,
            "devnet-cli",
            &format!("status-{height}"),
            "status_request",
            &json!({ "privacy": "roots_only" }),
            height,
            height.saturating_add(DEVNET_DEFAULT_RPC_TTL_BLOCKS),
        );
        self.rpc
            .receive_request(request.clone())
            .map_err(|error| error.message)?;
        let response_payload = json!({
            "daemon_root": self.daemon.daemon_root(),
            "height": height,
            "p2p_overlay_root": self.p2p.overlay_root(),
            "relayer_state_root": self.relayer.state_root(),
        });
        let response = self
            .rpc
            .produce_response(&request, "status_response", &response_payload, height)
            .map_err(|error| error.message)?;
        self.rpc_responses.push(response.clone());
        self.record_step(
            DevnetStepKind::RpcStatus,
            &request.public_record(),
            &response.public_record(),
            "ok",
        );
        Ok(response)
    }

    pub fn run_fee_quote(&mut self, height: u64) -> DevnetResult<Value> {
        let (_, quote, response) = self.daemon.low_fee_quote_via_api(
            LowFeeLane::monero_bridge_ops(),
            self.config.low_fee_gross_fee_units,
            "devnet-fee-client",
            &format!("fee-quote-{height}"),
        )?;
        self.fee_quotes.push(quote.clone());
        self.rpc_responses.push(RpcResponse::from_payload(
            &RpcRequest::from_payload(
                RpcMethod::LowFeeQuote,
                &quote,
                "devnet-fee-client",
                &format!("rpc-fee-quote-{height}"),
                "fee_quote_request",
                &json!({}),
                height,
                height.saturating_add(DEVNET_DEFAULT_RPC_TTL_BLOCKS),
            ),
            "fee_quote_response",
            &quote,
            &json!({ "api_response_id": response.response_id }),
            height,
        ));
        self.record_step(
            DevnetStepKind::FeeQuote,
            &json!({ "gross_fee_units": self.config.low_fee_gross_fee_units }),
            &quote,
            "ok",
        );
        Ok(quote)
    }

    pub fn run_p2p_sync(&mut self, summary: &SequencerBlockSummary) -> DevnetResult<()> {
        let local_peer_id = self.local_peer_id()?;
        let archive_peer_id = self.archive_peer_id()?;
        let request = self.p2p.open_sync_request(
            &local_peer_id,
            &archive_peer_id,
            summary.block_height.saturating_sub(2),
            summary.block_height,
            vec![
                "state_root".to_string(),
                "mempool_admission_root".to_string(),
                "monero_evidence_root".to_string(),
            ],
            true,
            true,
            true,
        )?;
        let selected_roots = json!({
            "block_hash": summary.block_hash,
            "state_root": summary.state_root,
            "da_root": summary.da_root,
            "mempool_admission_root": summary.mempool_admission_root,
            "consensus_state_root": summary.consensus_state_root,
        });
        let response = self.p2p.answer_sync_request_from_roots(
            &request.request_id,
            &archive_peer_id,
            &self.daemon.node.sequencer.network.root_inventory_root(),
            &self
                .daemon
                .node
                .sequencer
                .network
                .admission_inventory_root(),
            selected_roots,
            &self.daemon.node.sequencer.bridge.bridge_root(),
            &self.daemon.node.sequencer.monero.state_root(),
        )?;
        let gossip = self.p2p.build_gossip_message(
            &local_peer_id,
            "block_summary",
            summary.public_record(),
            "low_fee_private_relay",
            10,
            "low_fee",
            "roots_only",
        )?;
        self.p2p.enqueue_gossip(gossip)?;
        self.p2p
            .charge_bandwidth(&archive_peer_id, 4096, 2048, 1024)?;
        self.rpc.set_p2p_status_root(self.p2p.overlay_root());
        self.record_step(
            DevnetStepKind::P2pSync,
            &request.public_record(),
            &response.public_record(),
            "ok",
        );
        Ok(())
    }

    pub fn run_relayer_anchor(&mut self, summary: &SequencerBlockSummary) -> DevnetResult<()> {
        let endpoint_id = self
            .relayer
            .endpoints
            .keys()
            .next()
            .cloned()
            .ok_or_else(|| "devnet relayer endpoint missing".to_string())?;
        let anchor_payload = json!({
            "block_height": summary.block_height,
            "block_hash": summary.block_hash,
            "state_root": summary.state_root,
            "daemon_root": self.daemon.daemon_root(),
        });
        let job_id = self.relayer.schedule_anchor(
            &summary.block_hash,
            &summary.state_root,
            &anchor_payload,
            Some(endpoint_id.clone()),
            true,
        )?;
        self.relayer.mark_ready(&job_id)?;
        self.relayer.record_submission_attempt(&job_id)?;
        let receipt = self.relayer.record_observation(
            &job_id,
            &endpoint_id,
            summary.block_height,
            &format!("monero-block-{}", summary.block_height),
            &format!("monero-anchor-tx-{}", summary.block_height),
            20,
            &anchor_payload,
        )?;
        let _ = self.relayer.build_batch(
            RelayerJobKind::AnchorL2Block,
            8,
            &json!({ "anchor_job_id": job_id }),
        );
        self.record_step(
            DevnetStepKind::RelayerAnchor,
            &anchor_payload,
            &receipt.public_record(),
            "ok",
        );
        Ok(())
    }

    pub fn build_summary(&self, success: bool) -> DevnetRunSummary {
        let produced_block_root = merkle_root(
            "DEVNET-PRODUCED-BLOCK",
            &self
                .produced_blocks
                .iter()
                .map(SequencerBlockSummary::public_record)
                .collect::<Vec<_>>(),
        );
        let fee_quote_root = merkle_root("DEVNET-FEE-QUOTE", &self.fee_quotes);
        let rpc_response_root = merkle_root(
            "DEVNET-RPC-RESPONSE",
            &self
                .rpc_responses
                .iter()
                .map(RpcResponse::public_record)
                .collect::<Vec<_>>(),
        );
        let step_receipt_root = self.step_receipt_root();
        let l2_mvp_execution_control_plane_state_root =
            self.l2_mvp_execution_control_plane.state_root.clone();
        let private_l2_mvp_flow_orchestrator_state_root =
            self.private_l2_mvp_flow_orchestrator.state_root();
        let summary_id = devnet_summary_id(
            &self.config.run_id,
            self.daemon.node.height(),
            &produced_block_root,
            &self.daemon.daemon_root(),
            &step_receipt_root,
            &l2_mvp_execution_control_plane_state_root,
            &private_l2_mvp_flow_orchestrator_state_root,
        );
        DevnetRunSummary {
            summary_id,
            run_id: self.config.run_id.clone(),
            config_root: self.config.config_root(),
            final_height: self.daemon.node.height(),
            block_count: self.produced_blocks.len() as u64,
            step_count: self.step_receipts.len() as u64,
            produced_block_root,
            fee_quote_root,
            rpc_response_root,
            p2p_overlay_root: self.p2p.overlay_root(),
            relayer_state_root: self.relayer.state_root(),
            l2_mvp_execution_control_plane_state_root,
            private_l2_mvp_flow_orchestrator_state_root,
            state_accumulator_root: self.state.state_root(),
            daemon_root: self.daemon.daemon_root(),
            storage_manifest_root: self.daemon.storage.manifest_root(),
            step_receipt_root,
            success,
        }
    }

